int foo(int n)
/*@ Require 1 <= n && n < 100 && emp
    Ensure __return == n && emp
*/
{
    int cap = n + 2;
    int *out = malloc_int_array(cap);
    int k = 1;

    out[0] = 10;

    /*@ Inv Assert
        1 <= i && i <= n + 1 &&
        0 <= k && k <= cap - 1 &&
        IntArray::full(out, k, cons(10, nil)) *
        IntArray::undef_seg(out, k, cap)
    */
    for (int i = 1; i <= n; i++) {
        out[k] = 20;
        k = k + 1;

        /*@ Inv Assert
            1 <= i && i <= n + 1 &&
            0 <= k && k <= cap - 1 &&
            0 <= j && j <= 2 &&
            IntArray::full(out + k * sizeof(int), j, repeat_Z(0, j)) *
            IntArray::full(out, k, app(cons(10, nil), cons(20, nil))) *
            IntArray::undef_seg(out, k + j, cap)
        */
        for (int j = 0; j < 2; j++) {
            (out + k * sizeof(int))[j] = 0;
        }

        k = k + 2;
    }

    return k;
}

/*
Given a non-empty vector of integers arr && an integer k, return
the sum of the elements with at most two digits (in [-99, 99]) from the first k elements.

Example:
    Input: arr = {111,21,3,4000,5,6,7,8,9}, k = 4
    Output: 24   (21 + 3)
*/
#include "verification_stdlib.h"
#include "verification_list.h"
#include "int_array_def.h"

/*@ Extern Coq (problem_122_pre: list Z -> Z -> Prop)
               (problem_122_spec: list Z -> Z -> Z -> Prop)
               (sum_two_digit_upto: Z -> list Z -> Z)
               (sum_two_digit_int_range: Z -> list Z -> Prop) */
/*@ Import Coq Require Import p122_add_elements */

int p122_add_elements(int *arr, int arr_size, int k)
/*@ With lv
    Require
        1 <= arr_size && arr_size < INT_MAX &&
        1 <= k && k <= arr_size &&
        arr_size == Zlength(lv) &&
        problem_122_pre(lv, k) &&
        sum_two_digit_int_range(k, lv) &&
        IntArray::full(arr, arr_size, lv)
    Ensure
        problem_122_spec(lv, k, __return) &&
        IntArray::full(arr, arr_size, lv)
*/
{
    int s = 0;
    int i;

    /*@ Inv Assert
        arr == arr@pre && arr_size == arr_size@pre && k == k@pre &&
        1 <= arr_size@pre && arr_size@pre < INT_MAX &&
        1 <= k@pre && k@pre <= arr_size@pre &&
        arr_size@pre == Zlength(lv) &&
        problem_122_pre(lv, k@pre) &&
        sum_two_digit_int_range(k@pre, lv) &&
        0 <= i && i <= k@pre &&
        s == sum_two_digit_upto(i, lv) &&
        IntArray::full(arr, arr_size@pre, lv)
    */
    for (i = 0; i < k; i++)
        if (arr[i] >= -99 && arr[i] <= 99)
            s += arr[i];
    return s;
}

